export interface BrandLogoProps extends React.SVGProps<SVGSVGElement> {
  isDocking?: boolean;
}

const TextWrapper = ({
  children,
  delay,
  duration,
  center,
}: {
  children: React.ReactNode;
  delay: number;
  duration: number;
  center: number;
}) => {
  const processElement = (node: React.ReactNode): React.ReactNode => {
    if (!React.isValidElement(node)) return node;

    // If it's a Fragment, process its children recursively
    if (node.type === React.Fragment) {
      return React.Children.map((node.props as any).children, processElement);
    }

    // If it has children, process them
    if ((node.props as any).children) {
      return React.cloneElement(node, {
        children: React.Children.map((node.props as any).children, processElement),
      } as any);
    }

    // For individual paths, extract transform x-offset and calculate tracking expansion
    const transformStr = (node.props as any).transform || "";
    const match = transformStr.match(/translate\(([^,)]+)/);
    const x0 = match ? parseFloat(match[1]) : center;
    const dx = (x0 - center) * 0.06; // horizontal tracking factor

    return React.cloneElement(node, {
      custom: { delay, duration, dx },
    } as any);
  };

  return <>{React.Children.map(children, processElement)}</>;
};

export const BrandLogo = React.forwardRef<SVGSVGElement, BrandLogoProps>(
  ({ isDocking = false, ...props }, ref) => {
    const shouldReduceMotion = useReducedMotion();
    const scaleFactor = 1.0; // Draw scenes at original slower speed

    const drawVariants = {
      hidden: {
        pathLength: 0,
        opacity: 0,
        fillOpacity: 0,
        strokeOpacity: 0
      },
      visible: (custom: { delay: number; duration: number }) => {
        if (shouldReduceMotion) {
          return {
            pathLength: 1,
            opacity: 1,
            strokeOpacity: 1,
            fillOpacity: 1,
            transition: { duration: 0.1 }
          };
        }
        const scaledDelay = custom.delay * scaleFactor;
        const scaledDuration = custom.duration * scaleFactor;
        return {
          pathLength: 1,
          opacity: 1,
          strokeOpacity: 1,
          fillOpacity: 1,
          transition: {
            pathLength: {
              type: "tween",
              delay: scaledDelay,
              duration: scaledDuration,
              ease: [0.22, 1, 0.36, 1]
            },
            strokeOpacity: {
              type: "tween",
              delay: scaledDelay,
              duration: 0.1 * scaleFactor
            },
            fillOpacity: {
              type: "tween",
              delay: scaledDelay + scaledDuration * 0.45,
              duration: scaledDuration * 0.45,
              ease: [0.22, 1, 0.36, 1]
            },
            opacity: {
              type: "tween",
              delay: scaledDelay,
              duration: 0.1 * scaleFactor
            }
          }
        };
      }
    };

    const fadeVariants = {
      hidden: {
        opacity: 0,
        fillOpacity: 0
      },
      visible: (custom: { delay: number; duration: number }) => {
        if (shouldReduceMotion) {
          return {
            opacity: 1,
            fillOpacity: 1,
            transition: { duration: 0.1 }
          };
        }
        const scaledDelay = custom.delay * scaleFactor;
        const scaledDuration = custom.duration * scaleFactor;
        return {
          opacity: 1,
          fillOpacity: 1,
          transition: {
            opacity: {
              type: "tween",
              delay: scaledDelay + scaledDuration * 0.4,
              duration: 0.5 * scaleFactor,
              ease: [0.22, 1, 0.36, 1]
            },
            fillOpacity: {
              type: "tween",
              delay: scaledDelay + scaledDuration * 0.4,
              duration: 0.5 * scaleFactor,
              ease: [0.22, 1, 0.36, 1]
            }
          }
        };
      }
    };

    const textVariants = {
      hidden: (custom: any) => {
        if (shouldReduceMotion) {
          return {
            opacity: 0,
            y: 0,
            fillOpacity: 0,
            strokeOpacity: 0,
            x: 0
          };
        }
        return {
          opacity: 0,
          y: 8,
          fillOpacity: 0,
          strokeOpacity: 0,
          x: custom?.dx ? -custom.dx : 0
        };
      },
      visible: (custom: any) => {
        if (shouldReduceMotion) {
          return {
            opacity: 1,
            y: 0,
            fillOpacity: 1,
            strokeOpacity: 1,
            x: 0,
            transition: { duration: 0.4 }
          };
        }
        const scaledDelay = custom.delay * scaleFactor;
        const scaledDuration = custom.duration * scaleFactor;
        return {
          opacity: 1,
          y: 0,
          fillOpacity: 1,
          strokeOpacity: 1,
          x: 0,
          transition: {
            y: {
              type: "tween",
              delay: scaledDelay,
              duration: scaledDuration,
              ease: [0.22, 1, 0.36, 1]
            },
            x: {
              type: "tween",
              delay: scaledDelay,
              duration: scaledDuration,
              ease: [0.22, 1, 0.36, 1]
            },
            fillOpacity: {
              type: "tween",
              delay: scaledDelay + 0.1 * scaleFactor,
              duration: scaledDuration - 0.1 * scaleFactor,
              ease: [0.22, 1, 0.36, 1]
            },
            opacity: {
              type: "tween",
              delay: scaledDelay,
              duration: 0.2 * scaleFactor
            }
          }
        };
      }
    };

    const sweepVariants: any = {
      hidden: { x: "-100%" },
      sweep: {
        x: "200%",
        transition: {
          delay: 3.0 * scaleFactor,
          duration: 0.4 * scaleFactor,
          ease: "easeInOut" as any
        }
      }
    };

    return (
      <svg
        viewBox="0 0 1254 1254"
        ref={ref}
        xmlns="http://www.w3.org/2000/svg"
        {...props}
      >
        <defs>
          <linearGradient id="sweep-grad" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="white" stopOpacity={0} />
            <stop offset="50%" stopColor="white" stopOpacity={0.12} />
            <stop offset="100%" stopColor="white" stopOpacity={0} />
          </linearGradient>
          <clipPath id="logo-clip">
            <circle cx="627" cy="627" r="520" />
          </clipPath>
        </defs>

        <motion.g initial="hidden" animate="visible" id="logo-artwork">
          {/* 1. DNA */}
          <DnaPaths custom={{ delay: 0.4, duration: 0.8 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />

          {/* 2. Leaf */}
          <LeafPaths custom={{ delay: 0.7, duration: 0.8 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />

          {/* 3. Outer Green Ring */}
          <OuterRingGreenPaths custom={{ delay: 1.0, duration: 0.9 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />

          {/* 4. Outer Gold Ring */}
          <OuterRingGoldPaths custom={{ delay: 1.1, duration: 0.9 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />

          {/* 5. Hand */}
          <HandPaths custom={{ delay: 1.3, duration: 0.8 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />

          {/* 6. Icons Staggered */}
          <motion.g
            initial={{ opacity: 1 }}
            animate={{ opacity: 1 }}
          >
            <IconAyurvedaPaths custom={{ delay: 1.7, duration: 0.5 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />
            <IconMeditationPaths custom={{ delay: 1.8, duration: 0.5 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />
            <IconNutritionPaths custom={{ delay: 1.9, duration: 0.5 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />
            <IconMedicalPaths custom={{ delay: 2.0, duration: 0.5 }} drawVariants={drawVariants} fadeVariants={fadeVariants} />
          </motion.g>

          {/* 7. Text NIROGI TANMAN (with dynamic coordinate-based tracking wrapper) */}
          <motion.g
            initial={{ opacity: 1 }}
            animate={{ opacity: 1 }}
          >
            <TextWrapper delay={2.2} duration={0.6} center={618}>
              {TextNirogiPaths({ custom: { delay: 2.2, duration: 0.6 }, drawVariants: textVariants, fadeVariants })}
            </TextWrapper>
            <TextWrapper delay={2.4} duration={0.6} center={632}>
              {TextTanmanPaths({ custom: { delay: 2.4, duration: 0.6 }, drawVariants: textVariants, fadeVariants })}
            </TextWrapper>
          </motion.g>
        </motion.g>

        {/* 8. Light Sweep clipped to the SVG logo artwork */}
        <g clipPath="url(#logo-clip)" style={{ mixBlendMode: "plus-lighter" }}>
          <motion.rect
            width="100%"
            height="100%"
            fill="url(#sweep-grad)"
            variants={sweepVariants}
            initial="hidden"
            animate="sweep"
            style={{ pointerEvents: "none" }}
          />
        </g>
      </svg>
    );
  }
);

BrandLogo.displayName = "BrandLogo";
